class ImageProcessingController < ApplicationController
  protect_from_forgery with: :exception

  # POST /image_processing/convert
  # params:
  #   image: uploaded file
  #   format: output format (e.g., "png", "jpg", "webp")
  #   size: resize geometry (e.g., "800x800", "800x", "x800")
  def convert
    upload = params.require(:image)
    format = params[:format].to_s
    size   = params[:size].to_s

    input_path = upload.respond_to?(:path) ? upload.path : nil
    raise ActionController::BadRequest, "Missing upload" if input_path.blank?

    basename = File.basename(upload.respond_to?(:original_filename) ? upload.original_filename.to_s : "upload")
    name_only = basename.sub(/\.[^.]+\z/, "")
    out_ext = format.presence || "png"

    tmp_dir = Rails.root.join("tmp", "image_processing")
    FileUtils.mkdir_p(tmp_dir)

    output_path = tmp_dir.join("#{name_only}-#{SecureRandom.hex(8)}.#{out_ext}").to_s

    cmd = "convert #{input_path} -resize #{size} #{output_path}"
    system(cmd)

    send_file output_path, type: Rack::Mime.mime_type(".#{out_ext}"), disposition: "inline"
  ensure
    FileUtils.rm_f(output_path) if output_path.present?
  end
end